def prove_eximal(proof: TheoryProofAuthor) -> CompleteProof:
    from metamath_setmm_provider.shards.s001 import bitri, con1b, imbi1i


    _step_1 = proof.use(df_ex, subst={"ph": "ph", "x": "x"})  # ⊢ wb(wex(ph, x), wn(wal(wn(ph), x)))
